    name_en text,
    slug text,
    origin text,
    description text,
    fruit_size text,
    taste text,
    texture text,
    aroma text,
    harvest_season text,
    tree_vigor text,
    difficulty text,
    okinawa_suitability text,
    container_suitability text,
    beginner_suitability text,
    kenyu_comment text,
    public_notes text,
    private_notes text,
    is_public boolean,
    is_for_sale boolean
  )
)
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale)
select banana.id, new_cultivars.name_ja, new_cultivars.name_en, new_cultivars.slug, new_cultivars.origin, new_cultivars.description, new_cultivars.fruit_size, new_cultivars.taste, new_cultivars.texture, new_cultivars.aroma, new_cultivars.harvest_season, new_cultivars.tree_vigor, new_cultivars.difficulty, new_cultivars.okinawa_suitability, new_cultivars.container_suitability, new_cultivars.beginner_suitability, new_cultivars.kenyu_comment, new_cultivars.public_notes, new_cultivars.private_notes, new_cultivars.is_public, new_cultivars.is_for_sale
from new_cultivars
cross join banana;

